vulnerabilities.fix:
사용자로부터 입력받는 모든 문자열 데이터(예: 제목, 설명, 내용)는 데이터베이스에 저장하기 전 또는 렌더링하기 전에 반드시 적절히 새니타이징(sanitizing)하거나 HTML 이스케이프(escaping)해야 합니다. React 컴포넌트에서 `{text}` 형태로 직접 텍스트를 렌더링할 때는 기본적으로 HTML 이스케이프가 이루어지지만, `dangerouslySetInnerHTML`과 같은 속성을 사용하거나 서드파티 라이브러리를 통해 HTML을 렌더링할 경우 특히 주의해야 합니다. 가장 좋은 방법은 데이터를 저장하기 전에 서버 측(또는 클라이언트 측에서 신뢰할 수 있는 라이브러리)에서 잠재적인 악성 콘텐츠를 제거하는 것입니다.

**저장 전(입력 시) 새니타이징 예시 (DOMPurify 사용):**
```typescript
import DOMPurify from 'dompurify'; // npm install dompurify 또는 yarn add dompurify
// ...
const saveEvent = async (eventData: Partial<Event>) => {
  if (!user) return;

  // 사용자 입력 데이터를 저장하기 전에 새니타이징합니다.
  const sanitizedTitle = DOMPurify.sanitize(eventData.title || '');
  const sanitizedDescription = DOMPurify.sanitize(eventData.description || '');

  if (eventData.id) {
    await supabase
      .from('events')
      .update({
        title: sanitizedTitle, // 새니타이징된 데이터 사용
        description: sanitizedDescription, // 새니타이징된 데이터 사용
        date: eventData.date,
        start_time: eventData.start_time,
        end_time: eventData.end_time,
        color: eventData.color,
      })
      .eq('id', eventData.id);
  } // ... 이하 생략 (insert 부분도 동일하게 적용)
};

const saveMemo = async (memoData: Partial<Memo>) => {
  if (!user) return;

  const sanitizedTitle = DOMPurify.sanitize(memoData.title || '');
  const sanitizedContent = DOMPurify.sanitize(memoData.content || '');

  if (memoData.id) {
    await supabase
      .from('memos')
      .update({
        title: sanitizedTitle,
        content: sanitizedContent,
        color: memoData.color,
        updated_at: new Date().toISOString(),
      })
      .eq('id', memoData.id);
  } // ... 이하 생략 (insert 부분도 동일하게 적용)
};
```
